import type { ModelMessage } from "ai";
import { describe, expect, it } from "vitest";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types";

// Helper to create a minimal valid ModelMessage for testing
function createMockModelMessage(): ModelMessage {
  return {
    role: "user",
    content: "test message",
  };
}

// Helper to create a minimal valid Message for testing
function createMockMessage(): Message {
  return {
    id: "msg-1",
    createdAt: new Date("2025-01-01"),
    modelMessage: createMockModelMessage(),
  };
}

// Helper to create a minimal valid CompactionSummary for testing
function createMockCompactionSummary(): CompactionSummary {
  return {
    id: "summary-1",
    createdAt: new Date("2025-01-01"),
    summary: "test summary",
    summaryTokens: 100,
    tokensBefore: 500,
    firstKeptMessageId: "msg-1",
  };
}

describe("Message", () => {
  it("requires id, createdAt, and modelMessage fields", () => {
    const message: Message = {
      id: "msg-test",
      createdAt: new Date("2025-01-01T00:00:00Z"),
      modelMessage: createMockModelMessage(),
    };

    expect(message.id).toBe("msg-test");
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.modelMessage).toBeDefined();
  });

  it("allows optional originalContent field to be undefined", () => {
    const message: Message = {
      id: "msg-1",
      createdAt: new Date(),
      modelMessage: createMockModelMessage(),
    };

    expect(message.originalContent).toBeUndefined();
  });

  it("allows optional originalContent field to be set", () => {
    const message: Message = {
      id: "msg-1",
      createdAt: new Date(),
      modelMessage: createMockModelMessage(),
      originalContent: "original text",
    };

    expect(message.originalContent).toBe("original text");
  });

  it("type error when missing required fields", () => {
    // @ts-expect-error - missing required fields
    const _invalidMessage: Message = {
      id: "msg-1",
      // missing createdAt and modelMessage
    };
    expect(true).toBe(true); // compilation test
  });
});

describe("CheckpointMessage", () => {
  it("requires all core fields", () => {
    const checkpoint: CheckpointMessage = {
      id: "cp-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createMockModelMessage(),
    };

    expect(checkpoint.id).toBe("cp-1");
    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.isSummary).toBe(false);
    expect(checkpoint.message).toBeDefined();
  });

  it("allows optional isSummaryMessage field", () => {
    const checkpoint: CheckpointMessage = {
      id: "cp-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createMockModelMessage(),
    };

    expect(checkpoint.isSummaryMessage).toBeUndefined();
  });

  it("allows optional isSummaryMessage to be set", () => {
    const checkpoint: CheckpointMessage = {
      id: "cp-1",
      createdAt: Date.now(),
      isSummary: true,
      isSummaryMessage: true,
      message: createMockModelMessage(),
    };

    expect(checkpoint.isSummaryMessage).toBe(true);
  });

  it("allows optional originalContent field", () => {
    const checkpoint: CheckpointMessage = {
      id: "cp-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createMockModelMessage(),
      originalContent: "original",
    };

    expect(checkpoint.originalContent).toBe("original");
  });

  it("type error when missing required fields", () => {
    // @ts-expect-error - missing required fields
    const _invalid: CheckpointMessage = {
      id: "cp-1",
      // missing createdAt, isSummary, message
    };
    expect(true).toBe(true);
  });
});

describe("SessionMetadata", () => {
  it("requires all fields (no optional fields)", () => {
    const metadata: SessionMetadata = {
      sessionId: "session-1",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 100,
      completionTokens: 50,
      summaryMessageId: null,
    };

    expect(metadata.sessionId).toBe("session-1");
    expect(metadata.summaryMessageId).toBeNull();
  });

  it("allows summaryMessageId to be string or null", () => {
    const withSummary: SessionMetadata = {
      sessionId: "session-1",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 100,
      completionTokens: 50,
      summaryMessageId: "summary-1",
    };

    const noSummary: SessionMetadata = {
      sessionId: "session-2",
      createdAt: Date.now(),
      updatedAt: Date.now(),
      promptTokens: 100,
      completionTokens: 50,
      summaryMessageId: null,
    };

    expect(withSummary.summaryMessageId).toBe("summary-1");
    expect(noSummary.summaryMessageId).toBeNull();
  });

  it("type error when missing required fields", () => {
    // @ts-expect-error - missing required fields
    const _invalid: SessionMetadata = {
      sessionId: "session-1",
      // missing other required fields
    };
    expect(true).toBe(true);
  });
});

describe("CompactionConfig", () => {
  it("allows all fields to be optional (empty object is valid)", () => {
    const config: CompactionConfig = {};

    expect(config.enabled).toBeUndefined();
    expect(config.contextLimit).toBeUndefined();
    expect(config.maxTokens).toBeUndefined();
  });

  it("allows setting enabled field", () => {
    const config: CompactionConfig = {
      enabled: true,
    };

    expect(config.enabled).toBe(true);
  });

  it("allows setting contextLimit field", () => {
    const config: CompactionConfig = {
      contextLimit: 128000,
    };

    expect(config.contextLimit).toBe(128000);
  });

  it("allows setting maxTokens field", () => {
    const config: CompactionConfig = {
      maxTokens: 8000,
    };

    expect(config.maxTokens).toBe(8000);
  });

  it("allows setting reserveTokens field", () => {
    const config: CompactionConfig = {
      reserveTokens: 2000,
    };

    expect(config.reserveTokens).toBe(2000);
  });

  it("allows setting keepRecentTokens field", () => {
    const config: CompactionConfig = {
      keepRecentTokens: 2000,
    };

    expect(config.keepRecentTokens).toBe(2000);
  });

  it("allows setting thresholdRatio field (0-1)", () => {
    const config: CompactionConfig = {
      thresholdRatio: 0.5,
    };

    expect(config.thresholdRatio).toBe(0.5);
  });

  it("allows setting speculativeStartRatio field", () => {
    const config: CompactionConfig = {
      speculativeStartRatio: 0.5,
    };

    expect(config.speculativeStartRatio).toBe(0.5);
  });

  it("allows setting summarizeFn callback", () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages: ModelMessage[], prev?: string) => {
        return `summary of ${messages.length} messages`;
      },
    };

    expect(config.summarizeFn).toBeDefined();
    expect(typeof config.summarizeFn).toBe("function");
  });

  it("allows setting getStructuredState callback", () => {
    const config: CompactionConfig = {
      getStructuredState: () => "<todos><todo>test</todo></todos>",
    };

    expect(config.getStructuredState).toBeDefined();
    expect(config.getStructuredState()).toBe("<todos><todo>test</todo></todos>");
  });

  it("allows all fields together", () => {
    const config: CompactionConfig = {
      enabled: true,
      contextLimit: 128000,
      maxTokens: 8000,
      reserveTokens: 2000,
      keepRecentTokens: 2000,
      thresholdRatio: 0.5,
      speculativeStartRatio: 0.5,
      summarizeFn: async () => "summary",
      getStructuredState: () => "state",
    };

    expect(config.enabled).toBe(true);
    expect(config.contextLimit).toBe(128000);
    expect(config.maxTokens).toBe(8000);
  });
});

describe("PruningConfig", () => {
  it("allows all fields to be optional (empty object is valid)", () => {
    const config: PruningConfig = {};

    expect(config.enabled).toBeUndefined();
    expect(config.minSavingsTokens).toBeUndefined();
  });

  it("allows setting enabled field", () => {
    const config: PruningConfig = {
      enabled: true,
    };

    expect(config.enabled).toBe(true);
  });

  it("allows setting minSavingsTokens field", () => {
    const config: PruningConfig = {
      minSavingsTokens: 200,
    };

    expect(config.minSavingsTokens).toBe(200);
  });

  it("allows setting protectedToolNames field", () => {
    const config: PruningConfig = {
      protectedToolNames: ["read_file", "write_file"],
    };

    expect(config.protectedToolNames).toEqual(["read_file", "write_file"]);
  });

  it("allows setting protectRecentTokens field", () => {
    const config: PruningConfig = {
      protectRecentTokens: 2000,
    };

    expect(config.protectRecentTokens).toBe(2000);
  });

  it("allows setting replacementText field", () => {
    const config: PruningConfig = {
      replacementText: "[output pruned]",
    };

    expect(config.replacementText).toBe("[output pruned]");
  });
});

describe("ContinuationVariant", () => {
  it("accepts 'manual' value", () => {
    const variant: ContinuationVariant = "manual";
    expect(variant).toBe("manual");
  });

  it("accepts 'auto-with-replay' value", () => {
    const variant: ContinuationVariant = "auto-with-replay";
    expect(variant).toBe("auto-with-replay");
  });

  it("accepts 'tool-loop' value", () => {
    const variant: ContinuationVariant = "tool-loop";
    expect(variant).toBe("tool-loop");
  });

  it("type error for invalid value", () => {
    // @ts-expect-error - invalid variant value
    const _invalid: ContinuationVariant = "invalid";
    expect(true).toBe(true);
  });
});

describe("CompactionResult", () => {
  it("requires success, tokensBefore, and tokensAfter fields", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
    };

    expect(result.success).toBe(true);
    expect(result.tokensBefore).toBe(1000);
    expect(result.tokensAfter).toBe(500);
  });

  it("allows optional reason field", () => {
    const result: CompactionResult = {
      success: false,
      tokensBefore: 1000,
      tokensAfter: 1000,
      reason: "Compaction failed due to insufficient context",
    };

    expect(result.reason).toBe("Compaction failed due to insufficient context");
  });

  it("allows optional summaryMessageId field", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      summaryMessageId: "summary-1",
    };

    expect(result.summaryMessageId).toBe("summary-1");
  });

  it("allows optional continuationVariant field", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
      continuationVariant: "auto-with-replay",
    };

    expect(result.continuationVariant).toBe("auto-with-replay");
  });

  it("all optional fields are undefined by default", () => {
    const result: CompactionResult = {
      success: true,
      tokensBefore: 1000,
      tokensAfter: 500,
    };

    expect(result.reason).toBeUndefined();
    expect(result.summaryMessageId).toBeUndefined();
    expect(result.continuationVariant).toBeUndefined();
  });

  it("type error when missing required fields", () => {
    // @ts-expect-error - missing required fields
    const _invalid: CompactionResult = {
      success: true,
      // missing tokensBefore, tokensAfter
    };
    expect(true).toBe(true);
  });
});

describe("PreparedCompactionV2", () => {
  it("requires all non-optional fields", () => {
    const prepared: PreparedCompactionV2 = {
      baseMessageIds: ["msg-1", "msg-2"],
      revision: 1,
      splitIndex: 0,
      summaryText: "summary content",
      tokenDelta: -500,
    };

    expect(prepared.baseMessageIds).toEqual(["msg-1", "msg-2"]);
    expect(prepared.revision).toBe(1);
    expect(prepared.splitIndex).toBe(0);
    expect(prepared.summaryText).toBe("summary content");
    expect(prepared.tokenDelta).toBe(-500);
  });

  it("allows optional replayMessage field", () => {
    const checkpoint: CheckpointMessage = {
      id: "cp-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createMockModelMessage(),
    };

    const prepared: PreparedCompactionV2 = {
      baseMessageIds: ["msg-1"],
      revision: 1,
      splitIndex: 0,
      summaryText: "summary",
      tokenDelta: -100,
      replayMessage: checkpoint,
    };

    expect(prepared.replayMessage).toEqual(checkpoint);
  });

  it("replayMessage is undefined by default", () => {
    const prepared: PreparedCompactionV2 = {
      baseMessageIds: [],
      revision: 1,
      splitIndex: 0,
      summaryText: "",
      tokenDelta: 0,
    };

    expect(prepared.replayMessage).toBeUndefined();
  });

  it("type error when missing required fields", () => {
    // @ts-expect-error - missing required fields
    const _invalid: PreparedCompactionV2 = {
      baseMessageIds: [],
      // missing revision, splitIndex, summaryText, tokenDelta
    };
    expect(true).toBe(true);
  });
});

describe("ActualTokenUsage", () => {
  it("requires all fields (no optional fields)", () => {
    const usage: ActualTokenUsage = {
      promptTokens: 100,
      completionTokens: 50,
      totalTokens: 150,
