describe("SessionFileLine (discriminated union)", () => {
  it("SessionHeaderLine is assignable to SessionFileLine", () => {
    const header: SessionHeaderLine = {
      type: "header",
      version: 1,
      sessionId: "session-1",
      createdAt: Date.now(),
    };

    const line: SessionFileLine = header;
    expect(line.type).toBe("header");
  });

  it("MessageLine is assignable to SessionFileLine", () => {
    const message: MessageLine = {
      type: "message",
      id: "msg-1",
      createdAt: Date.now(),
      isSummary: false,
      message: createMockModelMessage(),
    };

    const line: SessionFileLine = message;
    expect(line.type).toBe("message");
  });

  it("CheckpointLine is assignable to SessionFileLine", () => {
    const checkpoint: CheckpointLine = {
      type: "checkpoint",
      summaryMessageId: "summary-1",
      updatedAt: Date.now(),
    };

    const line: SessionFileLine = checkpoint;
    expect(line.type).toBe("checkpoint");
  });

  it("type narrowing with type field", () => {
    const lines: SessionFileLine[] = [
      { type: "header", version: 1, sessionId: "s1", createdAt: 0 },
      { type: "message", id: "m1", createdAt: 0, isSummary: false, message: createMockModelMessage() },
      { type: "checkpoint", summaryMessageId: "sum1", updatedAt: 0 },
    ];

    for (const line of lines) {
      if (line.type === "header") {
        // TypeScript narrows to SessionHeaderLine
        expect(line.version).toBe(1);
        expect(line.sessionId).toBe("s1");
      } else if (line.type === "message") {
        // TypeScript narrows to MessageLine
        expect(line.id).toBe("m1");
        expect(line.isSummary).toBe(false);
      } else if (line.type === "checkpoint") {
        // TypeScript narrows to CheckpointLine
        expect(line.summaryMessageId).toBe("sum1");
      }
    }
  });

  it("switch statement with exhaustive check", () => {
    const processLine = (line: SessionFileLine): string => {
      switch (line.type) {
        case "header":
          return `header:${line.sessionId}`;
        case "message":
          return `message:${line.id}`;
        case "checkpoint":
          return `checkpoint:${line.summaryMessageId}`;
        default: {
          // Exhaustive check - this should never be reached
          const _exhaustive: never = line;
          return `unknown:${JSON.stringify(_exhaustive)}`;
        }
      }
    };

    const header: SessionFileLine = { type: "header", version: 1, sessionId: "s1", createdAt: 0 };
    expect(processLine(header)).toBe("header:s1");
  });
});

